(function () {
'use strict';
const API = '/api/notifications';
const state = { ready: false, items: [], unread: 0, timer: null, lastKeys: new Set() };
const $ = (selector, root = document) => root.querySelector(selector);
const safe = value => String(value ?? '').replace(/[&<>'"]/g, char => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#039;', '"': '&quot;' }[char]));
const number = value => new Intl.NumberFormat('vi-VN').format(Number(value || 0));
const toast = (message, type = 'info') => typeof window.showToast === 'function' ? window.showToast(message, type) : console[type === 'danger' ? 'error' : 'log'](message);
document.addEventListener('DOMContentLoaded', init);
document.addEventListener('thon09:auth-state', event => {
if (event.detail?.authenticated === false) clear();
else load();
});
function init() {
installShell();
bind();
load();
state.timer = window.setInterval(load, 60000);
}
function installShell() {
if (state.ready) return;
const button = $('#notificationBtn');
if (!button) return;
button.setAttribute('aria-expanded', 'false');
button.dataset.platformAction = 'notifications.toggle';
button.insertAdjacentHTML('afterend', '<section id="notificationPanel" class="notification-center-panel d-none" aria-label="Thong bao"><div class="notification-center-head"><strong>Thong bao</strong><button class="btn btn-sm btn-link" type="button" data-platform-action="notifications.readAll">Doc tat ca</button></div><div id="notificationRows" class="notification-center-list"></div><div class="notification-center-foot"><button class="btn btn-sm btn-outline-secondary" type="button" data-platform-action="notifications.permission"><i class="fa-solid fa-bell"></i> Bat thong bao he thong</button></div></section>');
if (!document.getElementById('notification-center-style')) {
const style = document.createElement('style');
style.id = 'notification-center-style';
style.textContent = '.gov-notification-btn{position:relative}.gov-notification-btn span{min-width:18px}.notification-center-panel{position:absolute;right:14px;top:58px;width:min(380px,calc(100vw - 24px));background:#fff;border:1px solid #dbe5ef;border-radius:10px;box-shadow:0 18px 42px rgba(15,23,42,.18);z-index:1060;overflow:hidden}.notification-center-head,.notification-center-foot{display:flex;align-items:center;justify-content:space-between;gap:8px;padding:10px 12px;background:#f8fafc;border-bottom:1px solid #e2e8f0}.notification-center-foot{border-top:1px solid #e2e8f0;border-bottom:0}.notification-center-list{display:grid;max-height:420px;overflow:auto}.notification-center-item{display:grid;grid-template-columns:auto minmax(0,1fr) auto;gap:9px;align-items:start;padding:10px 12px;border-bottom:1px solid #edf2f7;background:#fff;text-align:left}.notification-center-item.unread{background:#f0fdf4}.notification-center-item i{color:#0b6b3a;margin-top:3px}.notification-center-item strong{display:block;color:#172033;font-size:13px}.notification-center-item small{display:block;color:#64748b;font-size:12px}.notification-center-item .badge{align-self:center}.notification-center-actions{display:flex;gap:4px}.notification-center-empty{padding:18px 12px;color:#64748b;text-align:center}@media(max-width:640px){.notification-center-panel{position:fixed;left:12px;right:12px;top:58px;width:auto}.notification-center-list{max-height:70vh}}';
document.head.appendChild(style);
}
state.ready = true;
}
function bind() {
registerActions();
document.addEventListener('pointerdown', event => {
if (!event.target.closest('#notificationPanel') && !event.target.closest('#notificationBtn')) closePanel();
});
}
function registerActions() {
const actions = window.Thon09Platform?.actions;
if (!actions || window.__thon09NotificationActionsRegistered) return;
window.__thon09NotificationActionsRegistered = true;
actions
.register({ key: 'notifications.toggle', handler: toggle })
.register({ key: 'notifications.read', handler: ({ dataset }) => markRead(dataset.key || '', true) })
.register({ key: 'notifications.dismiss', handler: ({ dataset }) => dismiss(dataset.key || '') })
.register({ key: 'notifications.readAll', handler: readAll })
.register({ key: 'notifications.permission', handler: requestPermission });
}
async function api(path, options = {}) {
if (typeof window.api === 'function') return window.api(path, options);
const headers = { Accept: 'application/json' };
if (window.App?.token) headers.Authorization = `Bearer ${window.App.token}`;
if (window.App?.csrfToken) headers['X-CSRF-Token'] = window.App.csrfToken;
if (options.body) headers['Content-Type'] = 'application/json';
const response = await fetch(path, { method: options.method || 'GET', headers, body: options.body ? JSON.stringify(options.body) : undefined, cache: 'no-store' });
const payload = await response.json().catch(() => null);
if (!response.ok || payload?.ok === false) throw new Error(payload?.error?.message || payload?.message || 'Khong tai duoc thong bao');
return payload?.data ?? payload;
}
async function load() {
if (!$('#notificationBtn') || !window.App?.user) return;
try {
const data = await api(API + '?limit=50', { cacheTtl: 15000 });
const oldKeys = state.lastKeys;
state.items = data.items || [];
state.unread = Number(data.unread || 0);
state.lastKeys = new Set(state.items.map(item => item.key));
render();
notifyDesktop(state.items.filter(item => !item.is_read && !oldKeys.has(item.key)));
} catch (_) {
renderBadge(0);
}
}
function render() {
renderBadge(state.unread);
const host = $('#notificationRows');
if (!host) return;
if (!state.items.length) { host.innerHTML = '<div class="notification-center-empty">Chua co thong bao</div>'; return; }
host.innerHTML = state.items.map(item => `<article class="notification-center-item ${item.is_read ? '' : 'unread'}"><i class="fa-solid ${safe(item.icon || 'fa-bell')}"></i><button class="btn btn-link p-0 text-start" type="button" data-platform-action="notifications.read" data-key="${safe(item.key)}"><strong>${safe(item.title)}</strong><small>${safe(item.message)}</small></button><div class="notification-center-actions"><span class="badge bg-${item.priority === 'urgent' ? 'danger' : item.priority === 'high' ? 'warning' : 'secondary'}">${number(item.count)}</span><button class="btn btn-sm btn-link text-danger" type="button" data-platform-action="notifications.dismiss" data-key="${safe(item.key)}" title="An"><i class="fa-solid fa-xmark"></i></button></div></article>`).join('');
}
function renderBadge(count) {
const badge = $('#notificationBtn span');
if (!badge) return;
badge.textContent = count > 99 ? '99+' : String(count);
badge.classList.toggle('d-none', count <= 0);
}
function toggle() {
const panel = $('#notificationPanel');
const button = $('#notificationBtn');
if (!panel) return;
panel.classList.toggle('d-none');
button?.setAttribute('aria-expanded', String(!panel.classList.contains('d-none')));
if (!panel.classList.contains('d-none')) load();
}
function closePanel() {
$('#notificationPanel')?.classList.add('d-none');
$('#notificationBtn')?.setAttribute('aria-expanded', 'false');
}
async function markRead(key, navigate) {
if (!key) return;
await api(`${API}/${encodeURIComponent(key)}/read`, { method: 'POST' });
const item = state.items.find(row => row.key === key);
if (navigate && item?.screen) window.Thon09NavigationController?.navigate(item.screen);
await load();
}
async function dismiss(key) {
if (!key) return;
await api(`${API}/${encodeURIComponent(key)}/dismiss`, { method: 'POST' });
await load();
}
async function readAll() {
await api(API + '/read-all', { method: 'POST' });
toast('Da danh dau da doc', 'success');
await load();
}
async function requestPermission() {
if (!('Notification' in window)) return toast('Trinh duyet khong ho tro thong bao he thong', 'warning');
const permission = await Notification.requestPermission();
toast(permission === 'granted' ? 'Da bat thong bao he thong' : 'Chua cap quyen thong bao', permission === 'granted' ? 'success' : 'warning');
}
function notifyDesktop(items) {
if (!items.length || !('Notification' in window) || Notification.permission !== 'granted' || document.hidden === false) return;
items.slice(0, 3).forEach(item => new Notification(item.title, { body: item.message, tag: item.key, icon: '/assets/icons/icon-192.png' }));
}
function clear() {
state.items = [];
state.unread = 0;
state.lastKeys.clear();
renderBadge(0);
$('#notificationRows') && ($('#notificationRows').innerHTML = '');
}
window.loadNotificationsCenter = load;
})();
